import React, { useState } from 'react';
import { 
  Zap, 
  Paperclip, 
  Clock, 
  AlertCircle, 
  ThumbsUp, 
  ArrowLeft,
  FileText,
  Calendar,
  ChevronDown
} from 'lucide-react';

const NudgeDetails = ({ nudge, onUpdate }) => {
  const [showReschedule, setShowReschedule] = useState(false);
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedTimeRange, setSelectedTimeRange] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'high':
        return 'text-red-400';
      case 'normal':
        return 'text-yellow-400';
      case 'low':
        return 'text-green-400';
      default:
        return 'text-gray-400';
    }
  };

  const getPriorityIcon = (priority) => {
    switch (priority) {
      case 'high':
        return <AlertCircle className="w-4 h-4" />;
      case 'normal':
        return <Clock className="w-4 h-4" />;
      case 'low':
        return <Clock className="w-4 h-4" />;
      default:
        return <Clock className="w-4 h-4" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'online':
        return 'bg-green-500';
      case 'away':
        return 'bg-yellow-500';
      case 'offline':
        return 'bg-gray-500';
      default:
        return 'bg-gray-500';
    }
  };

  // Função para "Won't be able"
  const handleWontBeAble = () => {
    setShowReschedule(true);
  };

  // Função para confirmar reagendamento
  const handleConfirmReschedule = () => {
    if (selectedDate && selectedTimeRange) {
      setShowSuccess(true);
      setTimeout(() => {
        setShowSuccess(false);
        setShowReschedule(false);
        setSelectedDate('');
        setSelectedTimeRange('');
      }, 2000);
    }
  };

  // Função para voltar do reagendamento
  const backFromReschedule = () => {
    setShowReschedule(false);
    setSelectedDate('');
    setSelectedTimeRange('');
  };

  // Função para adicionar ao To-Do
  const handleAddToTodo = () => {
    // Implementar lógica para adicionar ao To-Do
    console.log('Added to To-Do:', nudge);
  };

  // Gerar opções de data (próximos 7 dias)
  const getDateOptions = () => {
    const dates = [];
    const today = new Date();

    for (let i = 1; i <= 7; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() + i);

      const dayName = date.toLocaleDateString('en-US', { weekday: 'long' });
      const dateStr = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

      dates.push({
        value: date.toISOString().split('T')[0],
        label: `${dayName}, ${dateStr}`
      });
    }

    return dates;
  };

  const timeRanges = [
    { value: 'morning', label: 'Morning (9:00 - 12:00)' },
    { value: 'afternoon', label: 'Afternoon (13:00 - 17:00)' },
    { value: 'evening', label: 'Evening (18:00 - 21:00)' }
  ];

  return (
    <div className="bg-neutral-700 rounded-lg h-full flex flex-col">
      {/* Header */}
      <div className="p-4 border-b border-neutral-600">
        <div className="flex items-center gap-3 mb-3">
          <div className="relative">
            <img 
              src={nudge.sender.avatar} 
              alt={nudge.sender.name}
              className="w-12 h-12 rounded-full object-cover"
            />
            <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-neutral-700 ${getStatusColor(nudge.sender.status)}`}></div>
          </div>

          <div className="flex-1 min-w-0">
            <h2 className="text-white font-medium text-lg">{nudge.sender.name}</h2>
            <p className="text-gray-400 text-sm">{nudge.sender.title}</p>
          </div>

          <div className="flex items-center gap-2">
            <div className={`flex items-center gap-1 ${getPriorityColor(nudge.priority)}`}>
              {getPriorityIcon(nudge.priority)}
            </div>
            <span className="text-gray-400 text-sm">{nudge.timestamp}</span>
          </div>
        </div>

        {/* Nudge indicator */}
        <div className="flex items-center gap-2">
          <div className="bg-yellow-500/20 p-2 rounded-lg">
            <Zap className="w-5 h-5 text-yellow-500" />
          </div>
          <span className="text-yellow-500 font-medium">Nudge Request</span>
          <div className={`ml-auto px-3 py-1 rounded-full text-xs font-medium ${
            nudge.priority === 'high' 
              ? 'bg-red-500/20 text-red-400' 
              : nudge.priority === 'normal'
              ? 'bg-yellow-500/20 text-yellow-400'
              : 'bg-green-500/20 text-green-400'
          }`}>
            {nudge.priority.charAt(0).toUpperCase() + nudge.priority.slice(1)} Priority
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto px-1 max-h-96">
        <div className="p-4">
          {/* Success Message */}
          {showSuccess && (
            <div className="mb-4 p-4 bg-green-500/20 border border-green-500/30 rounded-lg">
              <div className="flex items-center gap-2 text-green-400">
                <ThumbsUp className="w-5 h-5" />
                <span className="font-medium">Alternative time suggested!</span>
              </div>
              <p className="text-green-300 text-sm mt-1">
                Your suggestion has been sent to {nudge.sender.name}.
              </p>
            </div>
          )}

          {/* Reschedule Form */}
          {showReschedule && !showSuccess && (
            <div className="mb-4">
              <div className="flex items-center gap-2 mb-4">
                <button 
                  onClick={backFromReschedule}
                  className="p-1 hover:bg-neutral-600 rounded"
                >
                  <ArrowLeft className="w-4 h-4 text-gray-400" />
                </button>
                <h3 className="text-white font-medium">Suggest Alternative Time</h3>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-gray-300 text-sm font-medium mb-2">
                    Select Date
                  </label>
                  <div className="relative">
                    <select
                      value={selectedDate}
                      onChange={(e) => setSelectedDate(e.target.value)}
                      className="w-full bg-neutral-600 border border-neutral-500 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-blue-500 appearance-none"
                    >
                      <option value="">Choose a date...</option>
                      {getDateOptions().map(date => (
                        <option key={date.value} value={date.value}>
                          {date.label}
                        </option>
                      ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                  </div>
                </div>

                <div className="px-1">
                  <label className="block text-gray-300 text-sm font-medium mb-2">
                    Select Time Range
                  </label>
                  <div className="relative">
                    <select
                      value={selectedTimeRange}
                      onChange={(e) => setSelectedTimeRange(e.target.value)}
                      className="w-full bg-neutral-600 border border-neutral-500 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-blue-500 appearance-none"
                    >
                      <option value="">Choose a time range...</option>
                      {timeRanges.map(time => (
                        <option key={time.value} value={time.value}>
                          {time.label}
                        </option>
                      ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                  </div>
                </div>

                <button
                  onClick={handleConfirmReschedule}
                  disabled={!selectedDate || !selectedTimeRange}
                  className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 disabled:cursor-not-allowed text-white py-2 px-4 rounded-lg font-medium transition-colors"
                >
                  Send Suggestion
                </button>
              </div>
            </div>
          )}

          {/* Message Content */}
          {!showReschedule && !showSuccess && (
            <>
              <div className="mb-4">
                <h3 className="text-white font-medium mb-2">Message</h3>
                <div className="bg-neutral-600 rounded-lg p-3">
                  <p className="text-gray-300 leading-relaxed whitespace-pre-wrap">
                    {nudge.fullMessage}
                  </p>
                </div>
              </div>

              {/* Attachments */}
              {nudge.attachments && nudge.attachments.length > 0 && (
                <div className="mb-4">
                  <h3 className="text-white font-medium mb-2">Attachments</h3>
                  <div className="space-y-2">
                    {nudge.attachments.map((attachment, index) => (
                      <div key={index} className="flex items-center gap-3 bg-neutral-600 rounded-lg p-3 hover:bg-neutral-500 cursor-pointer transition-colors">
                        <FileText className="w-5 h-5 text-blue-400" />
                        <span className="text-gray-300 flex-1">{attachment}</span>
                        <Paperclip className="w-4 h-4 text-gray-400" />
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* Action Buttons */}
      {!showReschedule && !showSuccess && (
        <div className="p-4 border-t border-neutral-600">
          <div className="flex gap-3">
            <button
              onClick={handleAddToTodo}
              className="flex-1 bg-neutral-600 hover:bg-neutral-500 text-white py-3 px-4 rounded-lg font-medium transition-colors flex items-center justify-center gap-2"
            >
              <ThumbsUp className="w-4 h-4 text-black fill-current" />
              Add to my To-Do
            </button>
            <button
              onClick={handleWontBeAble}
              className="flex-1 bg-red-600 hover:bg-red-700 text-white py-3 px-4 rounded-lg font-medium transition-colors"
            >
              Won't be able
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default NudgeDetails;
